import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';
import chatRoute from './routes/chatRoute.js';
import diseasePredictionRoute from './routes/diseasePredictionRoute.js';

dotenv.config();

const app = express();
const PORT = process.env.PORT || 5000;

app.use(cors());
app.use(express.json());

app.use('/api/chat', chatRoute);
app.use('/api/disease-prediction', diseasePredictionRoute);

// Serve static graphs generated by the ML model
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
app.use('/graphs', express.static(path.join(__dirname, 'public/graphs')));

app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});


